// JS-callable surface for the RWKV-7 (SSM) recurrent pipeline.
//
// This mirrors `wasm_bindings::WasmLlamaPipeline` but for the linear-time
// State-Space Model path (`crate::model_rwkv7::RWKV7Pipeline`). The transformer
// wrapper carries a KV cache that grows one row per token; this one carries the
// RWKV-7 *recurrent state* — a fixed-size WKV matrix + token-shift + channel-mix
// vector per layer — so the checkpoint is **constant-size regardless of how many
// tokens have been generated**. That is the M5 O(1) headline made real on wasm.
//
// It reuses the existing `WasmHostBackend` (host-populated weight cache) verbatim
// via `WasmHostBackend::as_weight_backend`, so the JS host streams tensors with
// the same `set_tensor` / `tensor_info` flow the transformer path uses.
//
// Gated behind the `ssm-wasm` feature so the DEFAULT wasm build (the live
// transformer artifact in `apps/distributed-inference-worker/wasm`) is byte-for
// -byte unchanged. Build the SSM artifact separately with `--features ssm-wasm`.

use wasm_bindgen::prelude::*;

use crate::loader::KnotConfig;
use crate::model_rwkv7::{RWKV7LayerState, RWKV7Pipeline};
use crate::wasm_bindings::WasmHostBackend;

// Wire helpers (u32/f32/f16 frames + the binary16 conversions) live in
// `crate::f16_codec` — ungated, so the native test suite gates the conversions
// bit-exactly and native benches can time the codec. One codec, one home.
use crate::f16_codec::{put_f16s, put_f32s, put_u32, take_f16s, take_f32s, take_u32};

// ── the ONE per-layer f16 state frame ────────────────────────────────────────
// `f16 wkv | shift_x | channel_state | v_first` — shared by the per-layer shard
// wire (export/import_layer_state_f16, export/import_batch_layer_state_f16) and
// the per-lane whole-range checkpoint (export/import_batch_lane_state_f16), so
// there is exactly one codec for a layer's recurrent state on the f16 wire.
fn put_layer_state_f16(buf: &mut Vec<u8>, s: &RWKV7LayerState) {
    put_f16s(buf, &s.wkv);
    put_f16s(buf, &s.shift_x);
    put_f16s(buf, &s.channel_state);
    put_f16s(buf, &s.v_first);
}
fn take_layer_state_f16(b: &[u8], off: &mut usize, s: &mut RWKV7LayerState) {
    take_f16s(b, off, &mut s.wkv);
    take_f16s(b, off, &mut s.shift_x);
    take_f16s(b, off, &mut s.channel_state);
    take_f16s(b, off, &mut s.v_first);
}

/// Extract a readable message from a caught panic payload (the `catch_unwind`
/// hygiene every export uses so the JS host gets a real error string instead of
/// a bare `RuntimeError: unreachable`).
fn panic_msg(p: Box<dyn std::any::Any + Send>) -> String {
    p.downcast_ref::<String>()
        .cloned()
        .or_else(|| p.downcast_ref::<&'static str>().map(|s| s.to_string()))
        .unwrap_or_else(|| "unknown panic".to_string())
}

/// JS-facing RWKV-7 recurrent pipeline.
///
/// One per active session. The JS host owns the position counter and the
/// current token (same ownership split as the transformer log-rolling path);
/// this wrapper owns only the model weights + the O(1) recurrent state.
#[wasm_bindgen]
pub struct WasmRwkv7Pipeline {
    inner: RWKV7Pipeline,
    // Batched-station lane state (the windmill's ~L× width axis). `batch_xs`/`batch_vfs`
    // are the N lanes' carried residual + v_first; `batch_states` is `[layer][lane]` (only
    // the station's range is allocated). Empty until `init_batch`.
    batch_xs: Vec<Vec<f32>>,
    batch_vfs: Vec<Vec<f32>>,
    batch_states: Vec<Vec<RWKV7LayerState>>,
    // Station layer range [a, b) the batch skeleton was allocated for (`init_batch`
    // or a lazy `batch_add_lane`). One skeleton, one range — mixing ranges is a JS
    // error, never a silent state corruption.
    batch_range: Option<(u32, u32)>,
    // Batched lm_head cache: the selected lanes' final-normed residuals + the
    // selection itself, set by `stream_logits_begin_batch` and consumed by every
    // `stream_logits_shard_batch` (mirrors the solo `stream_normed` cache inside
    // `RWKV7Pipeline`).
    batch_normed: Vec<Vec<f32>>,
    batch_sel: Vec<u32>,
}

impl WasmRwkv7Pipeline {
    /// Wrap a freshly-built pipeline with an empty (uninitialized) batch surface.
    fn wrap(inner: RWKV7Pipeline) -> Self {
        Self {
            inner,
            batch_xs: Vec::new(),
            batch_vfs: Vec::new(),
            batch_states: Vec::new(),
            batch_range: None,
            batch_normed: Vec::new(),
            batch_sel: Vec::new(),
        }
    }
}

#[wasm_bindgen]
impl WasmRwkv7Pipeline {
    /// Borrow-construct from a host backend. Takes `&WasmHostBackend` (not by
    /// value) for the same reason as `WasmLlamaPipeline::from_backend`: taking
    /// the wrapper by value triggers wasm-bindgen `__destroy_into_raw` and
    /// invalidates the JS handle for subsequent `set_tensor` calls.
    ///
    /// `config_json` is a stringified `KnotConfig` (the output of
    /// `parse_config_json`). RWKV-7's low-rank / gate-inner dims are derived
    /// inside `from_knot` from the layer-0 tensor byte lengths, so the config
    /// only needs the coarse fields (`hidden_dim`, `num_layers`, `vocab_size`,
    /// `intermediate_size`, `arch`).
    #[wasm_bindgen]
    pub fn from_backend(
        backend: &WasmHostBackend,
        config_json: &str,
    ) -> Result<WasmRwkv7Pipeline, JsError> {
        console_error_panic_hook::set_once();
        let knot_cfg: KnotConfig = serde_json::from_str(config_json)
            .map_err(|e| JsError::new(&format!("config_json parse: {}", e)))?;
        let backend_dyn = backend.as_weight_backend();
        // Catch panics from missing-tensor `fetch_*` so the JS host gets a real
        // error string instead of a bare `RuntimeError: unreachable`.
        let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            RWKV7Pipeline::from_knot(&knot_cfg, backend_dyn)
        }));
        match result {
            Ok(inner) => Ok(Self::wrap(inner)),
            Err(p) => {
                let msg = p
                    .downcast_ref::<String>()
                    .cloned()
                    .or_else(|| p.downcast_ref::<&'static str>().map(|s| s.to_string()))
                    .unwrap_or_else(|| "unknown panic".to_string());
                Err(JsError::new(&format!(
                    "panic during RWKV7Pipeline::from_knot: {}",
                    msg
                )))
            }
        }
    }

    /// Streaming constructor — builds ONLY the small resident state; the host pages
    /// every layer's weights (`stream_layer`), the embedding row (`stream_embed`),
    /// and the lm_head shards (`stream_logits_shard`) on demand. Fits a 2.9B model
    /// in a 128MB isolate. The layer-0/1 RWKV tensors must be paged in before this
    /// call (low-rank dim derivation); the host may evict them after.
    #[wasm_bindgen]
    pub fn from_backend_streaming(
        backend: &WasmHostBackend,
        config_json: &str,
    ) -> Result<WasmRwkv7Pipeline, JsError> {
        console_error_panic_hook::set_once();
        let knot_cfg: KnotConfig = serde_json::from_str(config_json)
            .map_err(|e| JsError::new(&format!("config_json parse: {}", e)))?;
        let backend_dyn = backend.as_weight_backend();
        let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            RWKV7Pipeline::from_knot_streaming(&knot_cfg, backend_dyn)
        }));
        match result {
            Ok(inner) => Ok(Self::wrap(inner)),
            Err(p) => {
                let msg = p
                    .downcast_ref::<String>()
                    .cloned()
                    .or_else(|| p.downcast_ref::<&'static str>().map(|s| s.to_string()))
                    .unwrap_or_else(|| "unknown panic".to_string());
                Err(JsError::new(&format!(
                    "panic during RWKV7Pipeline::from_knot_streaming: {}",
                    msg
                )))
            }
        }
    }

    /// The vocabulary size (= logits length returned by `forward_one`).
    #[wasm_bindgen]
    pub fn vocab_size(&self) -> u32 {
        self.inner.config.vocab_size as u32
    }

    /// Number of layers (= recurrent-state blocks in a checkpoint).
    #[wasm_bindgen]
    pub fn num_layers(&self) -> u32 {
        self.inner.config.num_layers as u32
    }

    /// Forward ONE token through the linear-time recurrent scan. Advances every
    /// layer's O(1) state in place and returns the raw logits `[vocab_size]`.
    /// This is the SSM analogue of the transformer's full Embed→layers→LmHead
    /// program, collapsed into a single constant-work step.
    #[wasm_bindgen]
    pub fn forward_one(&mut self, token_id: u32) -> Result<Vec<f32>, JsError> {
        let vocab = self.inner.config.vocab_size;
        let mut logits = vec![0.0f32; vocab];
        let r = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            self.inner.forward_one(token_id, &mut logits);
        }));
        match r {
            Ok(()) => Ok(logits),
            Err(p) => {
                let msg = p
                    .downcast_ref::<String>()
                    .cloned()
                    .or_else(|| p.downcast_ref::<&'static str>().map(|s| s.to_string()))
                    .unwrap_or_else(|| "unknown panic".to_string());
                Err(JsError::new(&format!("panic during forward_one: {}", msg)))
            }
        }
    }

    /// Streaming token start: embed `token_id`'s row into the carried residual.
    /// Pair with `stream_layer(l)`×N + `stream_logits()` so the JS host can page
    /// each layer's weights from R2 between calls (fits a 2.9B model in a 128MB
    /// isolate). Resident `forward_one` is the all-in-memory equivalent.
    #[wasm_bindgen]
    pub fn stream_embed(&mut self, token_id: u32) {
        self.inner.stream_embed(token_id);
    }

    /// Streaming per-layer step: build layer `l`'s weights from the backend (the
    /// host must have `set_tensor`'d them just before this call), run the block,
    /// advance the layer's O(1) state, and drop the weights. catch_unwind so a
    /// missing/unpaged tensor surfaces as a JS error, not `unreachable`.
    #[wasm_bindgen]
    pub fn stream_layer(&mut self, layer: u32) -> Result<(), JsError> {
        let l = layer as usize;
        let r = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            self.inner.stream_layer(l);
        }));
        r.map_err(|p| {
            let msg = p
                .downcast_ref::<String>()
                .cloned()
                .or_else(|| p.downcast_ref::<&'static str>().map(|s| s.to_string()))
                .unwrap_or_else(|| "unknown panic".to_string());
            JsError::new(&format!("panic during stream_layer({}): {}", l, msg))
        })
    }

    /// Time-mix half of layer `l` (host paged ONLY the time-mix tensors). Peak
    /// resident ≈ the time-mix matrices, not a whole layer — pair with
    /// `stream_layer_channelmix(l)` to halve the per-layer memory ceiling.
    #[wasm_bindgen]
    pub fn stream_layer_timemix(&mut self, layer: u32) -> Result<(), JsError> {
        let l = layer as usize;
        let r = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            self.inner.stream_layer_timemix(l);
        }));
        r.map_err(|p| {
            let msg = p
                .downcast_ref::<String>()
                .cloned()
                .or_else(|| p.downcast_ref::<&'static str>().map(|s| s.to_string()))
                .unwrap_or_else(|| "unknown panic".to_string());
            JsError::new(&format!("panic during stream_layer_timemix({}): {}", l, msg))
        })
    }

    /// Channel-mix half of layer `l` (host paged ONLY the ffn tensors). Pair with
    /// `stream_layer_timemix(l)`.
    #[wasm_bindgen]
    pub fn stream_layer_channelmix(&mut self, layer: u32) -> Result<(), JsError> {
        let l = layer as usize;
        let r = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            self.inner.stream_layer_channelmix(l);
        }));
        r.map_err(|p| {
            let msg = p
                .downcast_ref::<String>()
                .cloned()
                .or_else(|| p.downcast_ref::<&'static str>().map(|s| s.to_string()))
                .unwrap_or_else(|| "unknown panic".to_string());
            JsError::new(&format!("panic during stream_layer_channelmix({}): {}", l, msg))
        })
    }

    /// Streaming token finish: final norm + lm_head over the carried residual →
    /// logits `[vocab_size]`.
    #[wasm_bindgen]
    pub fn stream_logits(&mut self) -> Vec<f32> {
        let mut logits = vec![0.0f32; self.inner.config.vocab_size];
        self.inner.stream_logits(&mut logits);
        logits
    }

    /// The lm_head source tensor the host pages in shards (`output_weight`, else
    /// tied `token_embd_weight`).
    #[wasm_bindgen]
    pub fn lm_src_name(&self) -> String {
        self.inner.lm_src_name()
    }

    /// Begin the streaming vocab-sharded lm_head (caches the final norm). Pair with
    /// `stream_logits_shard` over the host-paged shards of `lm_src_name()`.
    #[wasm_bindgen]
    pub fn stream_logits_begin(&mut self) {
        self.inner.stream_logits_begin();
    }

    /// Argmax over lm_head rows [row_lo, row_hi) — the host paged that shard as the
    /// tensor `lm_head_shard`. Returns `[best_global_idx, best_val]`; the host
    /// keeps the running max across shards.
    #[wasm_bindgen]
    pub fn stream_logits_shard(&self, row_lo: u32, row_hi: u32) -> Result<Vec<f32>, JsError> {
        let r = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            self.inner.stream_logits_shard(row_lo, row_hi)
        }));
        r.map_err(|p| {
            let msg = p
                .downcast_ref::<String>()
                .cloned()
                .or_else(|| p.downcast_ref::<&'static str>().map(|s| s.to_string()))
                .unwrap_or_else(|| "unknown panic".to_string());
            JsError::new(&format!("panic during stream_logits_shard: {}", msg))
        })
    }

    /// Greedy argmax of a logits vector — convenience so the JS host can decode
    /// without copying the whole vocab back across the boundary per token.
    #[wasm_bindgen]
    pub fn argmax(&self, logits: &[f32]) -> u32 {
        let mut best = 0usize;
        let mut best_v = f32::NEG_INFINITY;
        for (i, &v) in logits.iter().enumerate() {
            if v > best_v {
                best_v = v;
                best = i;
            }
        }
        best as u32
    }

    /// Reset every layer's recurrent state to zero (start a fresh sequence).
    #[wasm_bindgen]
    pub fn reset_states(&mut self) {
        self.inner.reset_states();
    }

    /// Size in bytes of a checkpoint produced by `snapshot_state` — the O(1)
    /// recurrent state, **independent of sequence position**. Exposed so the
    /// host/console can show the constant-size headline directly.
    #[wasm_bindgen]
    pub fn state_bytes(&self) -> u32 {
        let mut n = 4usize; // n_layers
        for s in &self.inner.states {
            n += 4 + s.wkv.len() * 4;
            n += 4 + s.shift_x.len() * 4;
            n += 4 + s.channel_state.len() * 4;
            n += 4 + s.v_first.len() * 4;
        }
        n as u32
    }

    /// Serialize the COMPLETE recurrent state of every layer (WKV matrix +
    /// token-shift + channel-mix + v_first). This is the resume-anywhere
    /// checkpoint: restoring it into a FRESH pipeline on a different host
    /// reproduces the exact continuation. Constant-size regardless of `pos`.
    #[wasm_bindgen]
    pub fn snapshot_state(&self) -> Vec<u8> {
        let mut buf = Vec::with_capacity(self.state_bytes() as usize);
        put_u32(&mut buf, self.inner.states.len() as u32);
        for s in &self.inner.states {
            put_f32s(&mut buf, &s.wkv);
            put_f32s(&mut buf, &s.shift_x);
            put_f32s(&mut buf, &s.channel_state);
            put_f32s(&mut buf, &s.v_first);
        }
        buf
    }

    /// Restore a checkpoint produced by `snapshot_state` into this pipeline.
    /// The weights must already be loaded (same model); only the recurrent
    /// state is overwritten.
    #[wasm_bindgen]
    pub fn restore_state(&mut self, bytes: &[u8]) -> Result<(), JsError> {
        if bytes.len() < 4 {
            return Err(JsError::new("restore_state: checkpoint too short"));
        }
        let mut off = 0usize;
        let n_layers = take_u32(bytes, &mut off) as usize;
        if n_layers != self.inner.states.len() {
            return Err(JsError::new(&format!(
                "restore_state: layer count mismatch (checkpoint {} vs model {})",
                n_layers,
                self.inner.states.len()
            )));
        }
        for l in 0..n_layers {
            let s = &mut self.inner.states[l];
            take_f32s(bytes, &mut off, &mut s.wkv);
            take_f32s(bytes, &mut off, &mut s.shift_x);
            take_f32s(bytes, &mut off, &mut s.channel_state);
            take_f32s(bytes, &mut off, &mut s.v_first);
        }
        Ok(())
    }

    /// fp16 twin of [`snapshot_state`](Self::snapshot_state) — the whole-pipe checkpoint
    /// at HALF the bytes (the SF/whole-pipe wire payload). Same layout, f16 storage.
    #[wasm_bindgen]
    pub fn snapshot_state_f16(&self) -> Vec<u8> {
        let mut buf = Vec::with_capacity(self.state_bytes() as usize / 2);
        put_u32(&mut buf, self.inner.states.len() as u32);
        for s in &self.inner.states {
            put_f16s(&mut buf, &s.wkv);
            put_f16s(&mut buf, &s.shift_x);
            put_f16s(&mut buf, &s.channel_state);
            put_f16s(&mut buf, &s.v_first);
        }
        buf
    }

    /// Restore an fp16 checkpoint produced by [`snapshot_state_f16`](Self::snapshot_state_f16).
    #[wasm_bindgen]
    pub fn restore_state_f16(&mut self, bytes: &[u8]) -> Result<(), JsError> {
        if bytes.len() < 4 {
            return Err(JsError::new("restore_state_f16: checkpoint too short"));
        }
        let mut off = 0usize;
        let n_layers = take_u32(bytes, &mut off) as usize;
        if n_layers != self.inner.states.len() {
            return Err(JsError::new(&format!(
                "restore_state_f16: layer count mismatch (checkpoint {} vs model {})",
                n_layers,
                self.inner.states.len()
            )));
        }
        for l in 0..n_layers {
            let s = &mut self.inner.states[l];
            take_f16s(bytes, &mut off, &mut s.wkv);
            take_f16s(bytes, &mut off, &mut s.shift_x);
            take_f16s(bytes, &mut off, &mut s.channel_state);
            take_f16s(bytes, &mut off, &mut s.v_first);
        }
        Ok(())
    }

    // ── Batch-lane ↔ solo checkpoint bridge (whole-pipe frame) ──────────────────
    // A depot wave lane's state, serialized in the EXACT `snapshot_state` frame —
    // so a lane checkpoint is a first-class SessionCheckpoint kv payload, portable
    // to/from every solo substrate (ssm-mini Workers solo, fat station, engine
    // restoreState). Lean contract: `Gnosis.InferenceMachineResume.checkpoint_resume`
    // (resuming from a checkpoint reproduces the uninterrupted continuation).

    /// Serialize ONE wave lane's recurrent state in the EXACT [`snapshot_state`]
    /// byte layout: `[u32 nLayers][per layer: f32 wkv | shift_x | channel_state |
    /// v_first]`. Requires a WHOLE-PIPE wave (`init_batch` range `[0, nLayers)`) —
    /// outside the range `batch_states[l]` is empty, so a partial-range wave cannot
    /// produce the solo frame. `v_first` is a per-token transient (empty at every
    /// token boundary on both the solo and batch paths), so its slot is a 0-length
    /// stub — kept in the frame for byte-exactness with `snapshot_state`.
    ///
    /// Lean: `Gnosis.InferenceMachineResume.checkpoint_resume`.
    #[wasm_bindgen]
    pub fn snapshot_lane_state(&self, lane: u32) -> Result<Vec<u8>, JsError> {
        let n_layers = self.inner.states.len();
        match self.batch_range {
            Some((0, b)) if b as usize == n_layers => {}
            _ => {
                return Err(JsError::new(
                    "snapshot_lane_state: lane checkpoint requires a whole-pipe wave (init range [0,nLayers))",
                ))
            }
        }
        let lane = lane as usize;
        let mut buf = Vec::with_capacity(self.state_bytes() as usize);
        put_u32(&mut buf, n_layers as u32);
        for l in 0..n_layers {
            let lanes = &self.batch_states[l];
            if lane >= lanes.len() {
                return Err(JsError::new(&format!(
                    "snapshot_lane_state: layer {l} has no lane {lane} (lanes: {})",
                    lanes.len()
                )));
            }
            let s = &lanes[lane];
            put_f32s(&mut buf, &s.wkv);
            put_f32s(&mut buf, &s.shift_x);
            put_f32s(&mut buf, &s.channel_state);
            put_f32s(&mut buf, &s.v_first);
        }
        Ok(buf)
    }

    /// Restore a [`snapshot_state`]-frame checkpoint (e.g. from a solo run, or
    /// from [`snapshot_lane_state`]) INTO wave lane `lane` — a solo session joins
    /// the wave mid-sequence. Mirror of [`restore_state`] targeting
    /// `batch_states[l][lane]`; requires the same whole-pipe wave.
    ///
    /// Lean: `Gnosis.InferenceMachineResume.checkpoint_resume`.
    #[wasm_bindgen]
    pub fn restore_lane_state(&mut self, lane: u32, bytes: &[u8]) -> Result<(), JsError> {
        let n_model = self.inner.states.len();
        match self.batch_range {
            Some((0, b)) if b as usize == n_model => {}
            _ => {
                return Err(JsError::new(
                    "restore_lane_state: lane checkpoint requires a whole-pipe wave (init range [0,nLayers))",
                ))
            }
        }
        if bytes.len() < 4 {
            return Err(JsError::new("restore_lane_state: checkpoint too short"));
        }
        let mut off = 0usize;
        let n_layers = take_u32(bytes, &mut off) as usize;
        if n_layers != n_model {
            return Err(JsError::new(&format!(
                "restore_lane_state: layer count mismatch (checkpoint {} vs model {})",
                n_layers, n_model
            )));
        }
        let lane = lane as usize;
        for l in 0..n_layers {
            if lane >= self.batch_states[l].len() {
                return Err(JsError::new(&format!(
                    "restore_lane_state: layer {l} has no lane {lane} (lanes: {})",
                    self.batch_states[l].len()
                )));
            }
        }
        // catch_unwind: a truncated payload panics inside take_f32s (slice OOB) —
        // surface it as a JS error, not `unreachable`.
        let r = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            for l in 0..n_layers {
                let s = &mut self.batch_states[l][lane];
                take_f32s(bytes, &mut off, &mut s.wkv);
                take_f32s(bytes, &mut off, &mut s.shift_x);
                take_f32s(bytes, &mut off, &mut s.channel_state);
                take_f32s(bytes, &mut off, &mut s.v_first);
            }
        }));
        r.map_err(|p| {
            JsError::new(&format!("panic during restore_lane_state: {}", panic_msg(p)))
        })
    }

    // ── Pinned-station I/O (stateless station; residual + state in the payload) ──
    // A fleet station holds a contiguous layer range resident and applies it to the
    // residual + state carried IN THE REQUEST. set_stream_x / set_stream_v_first +
    // import_layer_state(l) load the payload; stream_layer_timemix/channelmix(l) run
    // the resident range; get_stream_x / get_stream_v_first / export_layer_state(l)
    // read them back. The wire carries f32 residual + the range's compact state — no
    // weights (those stay warm in the station), no R2 on the hot path.
    #[wasm_bindgen]
    pub fn set_stream_x(&mut self, x: &[f32]) { self.inner.set_stream_x(x.to_vec()); }
    #[wasm_bindgen]
    pub fn get_stream_x(&self) -> Vec<f32> { self.inner.stream_x_ref().to_vec() }
    #[wasm_bindgen]
    pub fn set_stream_v_first(&mut self, v: &[f32]) { self.inner.set_stream_v_first(v.to_vec()); }
    #[wasm_bindgen]
    pub fn get_stream_v_first(&self) -> Vec<f32> { self.inner.stream_v_first_ref().to_vec() }

    /// Serialize ONE layer's recurrent state (wkv + shift_x + channel_state +
    /// v_first) — the station's per-layer state shard for the payload.
    #[wasm_bindgen]
    pub fn export_layer_state(&self, layer: u32) -> Vec<u8> {
        let s = self.inner.layer_state_ref(layer as usize);
        let mut buf = Vec::new();
        put_f32s(&mut buf, &s.wkv);
        put_f32s(&mut buf, &s.shift_x);
        put_f32s(&mut buf, &s.channel_state);
        put_f32s(&mut buf, &s.v_first);
        buf
    }

    /// Load ONE layer's recurrent state shard (inverse of export_layer_state).
    #[wasm_bindgen]
    pub fn import_layer_state(&mut self, layer: u32, bytes: &[u8]) -> Result<(), JsError> {
        let s = self.inner.layer_state_mut(layer as usize);
        let mut off = 0usize;
        take_f32s(bytes, &mut off, &mut s.wkv);
        take_f32s(bytes, &mut off, &mut s.shift_x);
        take_f32s(bytes, &mut off, &mut s.channel_state);
        take_f32s(bytes, &mut off, &mut s.v_first);
        Ok(())
    }

    /// fp16 twin of [`export_layer_state`](Self::export_layer_state) — the per-shard wire
    /// payload (the `shards` lane the windmill rides) at HALF the bytes.
    #[wasm_bindgen]
    pub fn export_layer_state_f16(&self, layer: u32) -> Vec<u8> {
        let mut buf = Vec::new();
        put_layer_state_f16(&mut buf, self.inner.layer_state_ref(layer as usize));
        buf
    }

    /// Load ONE layer's fp16 state shard (inverse of export_layer_state_f16).
    #[wasm_bindgen]
    pub fn import_layer_state_f16(&mut self, layer: u32, bytes: &[u8]) -> Result<(), JsError> {
        let mut off = 0usize;
        take_layer_state_f16(bytes, &mut off, self.inner.layer_state_mut(layer as usize));
        Ok(())
    }

    // ── Batched-station forward (the windmill's ~L× width axis) ─────────────────
    // A station holds layers [a,b) resident; `init_batch` allocates N lanes' state for
    // that range. The host loads each lane's residual/v_first/shards, `run_range_batch`
    // applies the resident range to ALL lanes with ONE weight read per row, then the host
    // reads each lane back. One batched call replaces N sequential per-lane station hops —
    // bit-identical, per lane, to the solo path (gated by rwkv7_batched_stream_station_parity).

    /// Allocate `n` lanes + per-lane recurrent state for the station's layer range `[a, b)`.
    #[wasm_bindgen]
    pub fn init_batch(&mut self, n: u32, a: u32, b: u32) {
        let n = n as usize;
        self.batch_xs = vec![Vec::new(); n];
        self.batch_vfs = vec![Vec::new(); n];
        self.batch_states = self.inner.new_batch_states_range(n, a as usize, b as usize);
        self.batch_range = Some((a, b));
        self.batch_normed.clear();
        self.batch_sel.clear();
    }

    /// Number of lanes currently allocated (0 before `init_batch`).
    #[wasm_bindgen]
    pub fn batch_lanes(&self) -> u32 { self.batch_xs.len() as u32 }

    /// Set lane `lane`'s carried residual (the wave-entry activation for this station).
    #[wasm_bindgen]
    pub fn set_batch_x(&mut self, lane: u32, x: &[f32]) { self.batch_xs[lane as usize] = x.to_vec(); }
    /// Set lane `lane`'s carried v_first (empty = entry station; layer 0 seeds it).
    #[wasm_bindgen]
    pub fn set_batch_v_first(&mut self, lane: u32, v: &[f32]) { self.batch_vfs[lane as usize] = v.to_vec(); }
    /// Read lane `lane`'s residual after `run_range_batch`.
    #[wasm_bindgen]
    pub fn get_batch_x(&self, lane: u32) -> Vec<f32> { self.batch_xs[lane as usize].clone() }
    /// Read lane `lane`'s v_first after `run_range_batch`.
    #[wasm_bindgen]
    pub fn get_batch_v_first(&self, lane: u32) -> Vec<f32> { self.batch_vfs[lane as usize].clone() }

    /// Import lane `lane`'s layer-`l` recurrent-state shard (fp16 wire).
    #[wasm_bindgen]
    pub fn import_batch_layer_state_f16(&mut self, lane: u32, l: u32, bytes: &[u8]) {
        let s = &mut self.batch_states[l as usize][lane as usize];
        let mut off = 0usize;
        take_layer_state_f16(bytes, &mut off, s);
    }
    /// Export lane `lane`'s layer-`l` recurrent-state shard (fp16 wire).
    #[wasm_bindgen]
    pub fn export_batch_layer_state_f16(&self, lane: u32, l: u32) -> Vec<u8> {
        let mut buf = Vec::new();
        put_layer_state_f16(&mut buf, &self.batch_states[l as usize][lane as usize]);
        buf
    }

    /// One-call PER-LANE checkpoint over the station range `[a, b)` (fp16 wire):
    /// `[u32 nLayers = b-a][per layer: f16 wkv | shift_x | channel_state | v_first]`
    /// — each layer uses the exact `export_batch_layer_state_f16` frame, so a lane
    /// leaving the wave ships its whole range in one call instead of `b-a`.
    #[wasm_bindgen]
    pub fn export_batch_lane_state_f16(&self, lane: u32, a: u32, b: u32) -> Result<Vec<u8>, JsError> {
        let lane = lane as usize;
        let (a, b) = (a as usize, b as usize);
        if a > b || b > self.batch_states.len() {
            return Err(JsError::new(&format!(
                "export_batch_lane_state_f16: bad range [{a}, {b}) (layers: {})",
                self.batch_states.len()
            )));
        }
        let mut buf = Vec::new();
        put_u32(&mut buf, (b - a) as u32);
        for l in a..b {
            let lanes = &self.batch_states[l];
            if lane >= lanes.len() {
                return Err(JsError::new(&format!(
                    "export_batch_lane_state_f16: layer {l} has no lane {lane} (lanes: {})",
                    lanes.len()
                )));
            }
            put_layer_state_f16(&mut buf, &lanes[lane]);
        }
        Ok(buf)
    }

    /// Restore a lane checkpoint produced by [`export_batch_lane_state_f16`]
    /// (inverse) — a lane joining the wave resumes its sequence in one call.
    #[wasm_bindgen]
    pub fn import_batch_lane_state_f16(
        &mut self,
        lane: u32,
        a: u32,
        b: u32,
        bytes: &[u8],
    ) -> Result<(), JsError> {
        let lane = lane as usize;
        let (a, b) = (a as usize, b as usize);
        if bytes.len() < 4 {
            return Err(JsError::new("import_batch_lane_state_f16: checkpoint too short"));
        }
        let mut off = 0usize;
        let n_layers = take_u32(bytes, &mut off) as usize;
        if a > b || n_layers != b - a {
            return Err(JsError::new(&format!(
                "import_batch_lane_state_f16: layer count mismatch (checkpoint {n_layers} vs range [{a}, {b}))"
            )));
        }
        if b > self.batch_states.len() {
            return Err(JsError::new(&format!(
                "import_batch_lane_state_f16: range [{a}, {b}) exceeds layers ({})",
                self.batch_states.len()
            )));
        }
        for l in a..b {
            if lane >= self.batch_states[l].len() {
                return Err(JsError::new(&format!(
                    "import_batch_lane_state_f16: layer {l} has no lane {lane} (lanes: {})",
                    self.batch_states[l].len()
                )));
            }
        }
        // catch_unwind: a truncated payload panics inside take_f16s (slice OOB) —
        // surface it as a JS error, not `unreachable`.
        let r = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            for l in a..b {
                take_layer_state_f16(bytes, &mut off, &mut self.batch_states[l][lane]);
            }
        }));
        r.map_err(|p| {
            JsError::new(&format!("panic during import_batch_lane_state_f16: {}", panic_msg(p)))
        })
    }

    /// Zero the range's recurrent state for token 0 (no input shards seed it).
    #[wasm_bindgen]
    pub fn reset_batch_range(&mut self, a: u32, b: u32) {
        for l in (a as usize)..(b as usize) {
            for lane in self.batch_states[l].iter_mut() {
                lane.wkv.iter_mut().for_each(|v| *v = 0.0);
                lane.shift_x.iter_mut().for_each(|v| *v = 0.0);
                lane.channel_state.iter_mut().for_each(|v| *v = 0.0);
                lane.v_first.clear();
            }
        }
    }

    /// Run the station's resident layer range `[a, b)` over ALL lanes — one weight
    /// page+dequant per row serves the whole wave (the `~L×` amortization, vs N solo hops).
    /// catch_unwind so an unpaged tensor / bad range surfaces as a JS error, not
    /// `unreachable`.
    #[wasm_bindgen]
    pub fn run_range_batch(&mut self, a: u32, b: u32) -> Result<(), JsError> {
        let r = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            for l in (a as usize)..(b as usize) {
                self.inner
                    .stream_layer_timemix_batch(l, &mut self.batch_xs, &mut self.batch_vfs, &mut self.batch_states[l]);
                self.inner
                    .stream_layer_channelmix_batch(l, &mut self.batch_xs, &mut self.batch_states[l]);
            }
        }));
        r.map_err(|p| JsError::new(&format!("panic during run_range_batch: {}", panic_msg(p))))
    }

    // ── Lane lifecycle (continuous batching: lanes join/leave a live wave) ──────
    // The lane vecs live HERE (the bindings own the wave roster); the mutation math
    // lives on `RWKV7Pipeline` (natively tested) and these entries just delegate.
    // Add/remove/reset touch ONLY the named lane's slot — never another lane's state
    // (`Gnosis.VGpuWarp.batch_isolation`).

    /// Append ONE fresh zero-state lane for the station range `[a, b)`; returns the
    /// new lane's index. Lazily allocates an empty skeleton on first use (no
    /// `init_batch` required); a skeleton for a DIFFERENT range is a JS error —
    /// one skeleton, one range.
    #[wasm_bindgen]
    pub fn batch_add_lane(&mut self, a: u32, b: u32) -> Result<u32, JsError> {
        match self.batch_range {
            None => {
                // First lane ever: width-0 skeleton for [a, b), then push below.
                self.batch_xs = Vec::new();
                self.batch_vfs = Vec::new();
                self.batch_states = self.inner.new_batch_states_range(0, a as usize, b as usize);
                self.batch_range = Some((a, b));
            }
            Some((ea, eb)) if (ea, eb) != (a, b) => {
                return Err(JsError::new(&format!(
                    "batch_add_lane: range [{a}, {b}) does not match the live batch range [{ea}, {eb})"
                )));
            }
            Some(_) => {}
        }
        let lane = self.inner.batch_add_lane(
            &mut self.batch_xs,
            &mut self.batch_vfs,
            &mut self.batch_states,
            a as usize,
            b as usize,
        );
        Ok(lane as u32)
    }

    /// Remove lane `lane` (swap-remove across every per-layer state vec + the
    /// residual/v_first vecs — O(1), order-NOT-preserving). Returns the OLD index of
    /// the lane that moved into the vacated slot (== `lane` if it was last) so the
    /// host re-points its session→lane map.
    #[wasm_bindgen]
    pub fn batch_remove_lane(&mut self, lane: u32) -> Result<u32, JsError> {
        let n = self.batch_xs.len();
        if lane as usize >= n {
            return Err(JsError::new(&format!(
                "batch_remove_lane: lane {lane} out of range (lanes: {n})"
            )));
        }
        let moved = RWKV7Pipeline::batch_remove_lane(
            &mut self.batch_xs,
            &mut self.batch_vfs,
            &mut self.batch_states,
            lane as usize,
        );
        // The cached lm_head selection indexes lanes by position — a removal
        // invalidates it (the host re-begins after a roster change).
        self.batch_normed.clear();
        self.batch_sel.clear();
        Ok(moved as u32)
    }

    /// Zero lane `lane`'s recurrent state over `[a, b)` — a fresh sequence joining
    /// the wave mid-flight reuses the slot without reallocating.
    #[wasm_bindgen]
    pub fn batch_reset_lane(&mut self, lane: u32, a: u32, b: u32) -> Result<(), JsError> {
        let n = self.batch_xs.len();
        if lane as usize >= n {
            return Err(JsError::new(&format!(
                "batch_reset_lane: lane {lane} out of range (lanes: {n})"
            )));
        }
        for l in (a as usize)..(b as usize) {
            if l >= self.batch_states.len() || (lane as usize) >= self.batch_states[l].len() {
                return Err(JsError::new(&format!(
                    "batch_reset_lane: layer {l} has no lane {lane} state (range mismatch?)"
                )));
            }
        }
        RWKV7Pipeline::batch_reset_lane(&mut self.batch_states, lane as usize, a as usize, b as usize);
        Ok(())
    }

    // ── Batched lm_head (amortize the vocab-shard sweep across the wave) ────────

    /// Begin the BATCHED vocab-sharded lm_head: final-norm each SELECTED lane's
    /// residual into the cached batch (mirrors the solo `stream_logits_begin`
    /// cache). `lanes` picks which lanes decode this token — a lane still
    /// prefilling isn't ready to decode with the rest of the wave.
    #[wasm_bindgen]
    pub fn stream_logits_begin_batch(&mut self, lanes: &[u32]) -> Result<(), JsError> {
        let n = self.batch_xs.len();
        for &k in lanes {
            if k as usize >= n {
                return Err(JsError::new(&format!(
                    "stream_logits_begin_batch: lane {k} out of range (lanes: {n})"
                )));
            }
        }
        // catch_unwind: a wrong-length residual (bad set_batch_x) panics inside the
        // norm — surface it as a JS error, not `unreachable`.
        let r = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            lanes
                .iter()
                .map(|&k| self.inner.final_norm(&self.batch_xs[k as usize]))
                .collect::<Vec<_>>()
        }));
        match r {
            Ok(normed) => {
                self.batch_normed = normed;
                self.batch_sel = lanes.to_vec();
                Ok(())
            }
            Err(p) => Err(JsError::new(&format!(
                "panic during stream_logits_begin_batch: {}",
                panic_msg(p)
            ))),
        }
    }

    /// The lane selection cached by `stream_logits_begin_batch` (in call order) —
    /// the order `stream_logits_shard_batch`'s per-lane pairs come back in.
    #[wasm_bindgen]
    pub fn batch_selected(&self) -> Vec<u32> {
        self.batch_sel.clone()
    }

    /// Batched twin of `stream_logits_shard`: argmax over lm_head rows
    /// [row_lo, row_hi) (host paged the shard as `lm_head_shard`) for EVERY selected
    /// lane — ONE dequant per row serves the whole wave
    /// (`Gnosis.WarpBatchAmortization.sharedCost`). Returns the solo
    /// `[best_global_idx, best_val]` convention PER lane, flat in `lanes` order:
    /// `[idx_0, val_0, idx_1, val_1, …]`; the host keeps each lane's running max
    /// across shards.
    #[wasm_bindgen]
    pub fn stream_logits_shard_batch(&self, row_lo: u32, row_hi: u32) -> Result<Vec<f32>, JsError> {
        if self.batch_normed.is_empty() {
            return Err(JsError::new(
                "stream_logits_shard_batch: call stream_logits_begin_batch first",
            ));
        }
        let r = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            self.inner
                .stream_logits_shard_batch(row_lo, row_hi, &self.batch_normed)
        }));
        r.map_err(|p| {
            JsError::new(&format!("panic during stream_logits_shard_batch: {}", panic_msg(p)))
        })
    }
}
